#!/usr/bin/env bash
# Generated by /adopt-dev-env — re-run to regenerate from repo inspection.
# Edit manually for project-specific overrides that auto-detection cannot infer.

PROJECT_NAME="my-project"
DEV_ROOT="/tmp/${PROJECT_NAME}-dev"
LOG_DIR="$DEV_ROOT/logs"
RUN_DIR="$DEV_ROOT/run"

# Processes launched in parallel by up.sh / stopped by down.sh.
# Format: "name|command"  (name is used as the PID file stem and log prefix)
PROCESSES=(
  "app|npm run dev"
)

# Infrastructure lifecycle — run before / after PROCESSES.
# Examples: "docker compose up -d", "make infra-up", ""  (empty = no infra step)
INFRA_UP_CMD="docker compose up -d"
INFRA_DOWN_CMD="docker compose down"

# Ports checked by status.sh and killed by down.sh on teardown.
# Format: "label|port"
PORTS=(
  "app|3000"
)
